export class CircuitBreaker {
  #failures = 0;
  #state = 'closed';
  #openedAt = null;

  constructor({ threshold = 2, cooldownMs = 1000 } = {}) {
    if (!Number.isInteger(threshold) || threshold < 1) throw new TypeError('invalid threshold');
    if (!Number.isFinite(cooldownMs) || cooldownMs < 0) throw new TypeError('invalid cooldown');
    this.threshold = threshold;
    this.cooldownMs = cooldownMs;
  }

  canRequest(now) {
    if (this.#state === 'open' && now - this.#openedAt >= this.cooldownMs) {
      this.#state = 'half-open';
    }
    return this.#state !== 'open';
  }

  success() {
    this.#failures = 0;
    this.#state = 'closed';
    this.#openedAt = null;
  }

  failure(now) {
    this.#failures += 1;
    if (this.#state === 'half-open' || this.#failures >= this.threshold) {
      this.#state = 'open';
      this.#openedAt = now;
    }
  }

  snapshot() {
    return { state: this.#state, failures: this.#failures, openedAt: this.#openedAt };
  }
}

