export class CircuitOpenError extends Error {
  constructor() {
    super('backend circuit is open');
    this.name = 'CircuitOpenError';
  }
}

export class ClientInputError extends Error {
  constructor(message) {
    super(message);
    this.name = 'ClientInputError';
  }
}

