import { CircuitOpenError } from './client-errors.mjs';

export async function callService(operation, breaker, now = Date.now) {
  if (!breaker.canRequest(now())) throw new CircuitOpenError();
  try {
    const result = await operation();
    breaker.success();
    return result;
  } catch (error) {
    breaker.failure(now());
    throw error;
  }
}

