import test from 'node:test';
import assert from 'node:assert/strict';

import { CircuitBreaker } from '../src/circuit-breaker.mjs';
import { CircuitOpenError } from '../src/client-errors.mjs';
import { callService } from '../src/service-client.mjs';

test('closed calls succeed and remote failures open at the threshold', async () => {
  const breaker = new CircuitBreaker({ threshold: 2, cooldownMs: 50 });
  assert.equal(await callService(async () => 'ok', breaker, () => 0), 'ok');
  await assert.rejects(callService(async () => { throw new Error('one'); }, breaker, () => 1));
  await assert.rejects(callService(async () => { throw new Error('two'); }, breaker, () => 2));
  assert.deepEqual(breaker.snapshot(), { state: 'open', failures: 2, openedAt: 2 });
  await assert.rejects(callService(async () => 'late', breaker, () => 20), CircuitOpenError);
});
